descriptor.templateCss:
#freat-card {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  font-family: 'Roboto', sans-serif;
  padding: 16px;
  box-sizing: border-box;
}
.fc-label {
  font-size: 13px;
  color: #888;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 4px;
}
.fc-value {
  font-size: 52px;
  font-weight: 300;
  line-height: 1;
  margin-bottom: 4px;
}
.fc-unit {
  font-size: 16px;
  color: #aaa;
  margin-bottom: 12px;
}
.fc-bar-wrap {
  width: 80%;
  max-width: 220px;
  height: 8px;
  background: #e8f5e9;
  border-radius: 6px;
  overflow: hidden;
  margin-bottom: 4px;
}
.fc-bar {
  height: 100%;
  border-radius: 6px;
  transition: width 0.5s ease;
}
.fc-bar-labels {
  width: 80%;
  max-width: 220px;
  display: flex;
  justify-content: space-between;
  font-size: 10px;
  color: #ccc;
  margin-bottom: 10px;
}
.fc-badge {
  padding: 2px 12px;
  border-radius: 12px;
  font-size: 12px;
  font-weight: 500;
  margin-bottom: 6px;
}
.badge-ok  { background: #E8F5E9; color: #2E7D32; }
.badge-low { background: #FFF3E0; color: #E65100; }
.badge-crit{ background: #FFEBEE; color: #C62828; }
.fc-ts {
  font-size: 11px;
  color: #ccc;
}

descriptor.controllerScript:
var RANGO_MAX = 20;

self.onInit = function() {
  var el = document.getElementById('freat-card');
  el.innerHTML =
    '<div class="fc-label">Nivel freático</div>' +
    '<div class="fc-value" id="fc-val" style="color:#1D9E75">--</div>' +
    '<div class="fc-unit">metros</div>' +
    '<div class="fc-bar-wrap"><div class="fc-bar" id="fc-bar" style="width:0%;background:#1D9E75"></div></div>' +
    '<div class="fc-bar-labels"><span>0 m</span><span>' + RANGO_MAX + ' m</span></div>' +
    '<div class="fc-badge badge-ok" id="fc-badge">Sin datos</div>' +
    '<div class="fc-ts" id="fc-ts"></div>';
};

self.onDataUpdated = function() {
  var data = self.ctx.data;
  var val = null, ts = null;

  for (var i = 0; i < data.length; i++) {
    if (data[i].dataKey.name === 'columna_agua_m' && data[i].data.length > 0) {
      var last = data[i].data[data[i].data.length - 1];
      val = parseFloat(last[1]);
      ts  = last[0];
    }
  }

  var valEl   = document.getElementById('fc-val');
  var barEl   = document.getElementById('fc-bar');
  var badgeEl = document.getElementById('fc-badge');
  var tsEl    = document.getElementById('fc-ts');

  if (val !== null && !isNaN(val)) {
    valEl.textContent = val.toFixed(2);
    var pct = Math.min(100, Math.max(0, (val / RANGO_MAX) * 100));
    barEl.style.width = pct + '%';

    badgeEl.className = 'fc-badge';
    if (val <= RANGO_MAX * 0.10) {
      badgeEl.classList.add('badge-crit');
      badgeEl.textContent = 'Nivel crítico';
      barEl.style.background = '#E24B4A';
      valEl.style.color = '#E24B4A';
    } else if (val <= RANGO_MAX * 0.25) {
      badgeEl.classList.add('badge-low');
      badgeEl.textContent = 'Nivel bajo';
      barEl.style.background = '#EF9F27';
      valEl.style.color = '#EF9F27';
    } else {
      badgeEl.classList.add('badge-ok');
      badgeEl.textContent = 'Normal';
      barEl.style.background = '#1D9E75';
      valEl.style.color = '#1D9E75';
    }

    if (ts) {
      var d = new Date(ts);
      tsEl.textContent = 'Actualizado: ' + d.toLocaleString('es-AR');
    }
  }
};

self.onResize = function() {};
self.onDestroy = function() {};

